import React from 'react';
import { BrowserRouter, Link, Navigate, Route, Routes } from 'react-router-dom';
import {
  AppBar,
  Box,
  Button,
  Card,
  CardContent,
  Container,
  CssBaseline,
  Stack,
  Toolbar,
  Typography,
} from '@mui/material';
import { ThemeProvider, createTheme } from '@mui/material/styles';

const theme = createTheme({
  palette: {
    mode: 'dark',
    primary: { main: '#4f8cff' },
    background: {
      default: '#08111f',
      paper: 'rgba(10, 18, 34, 0.84)',
    },
  },
  typography: {
    fontFamily: 'Inter, system-ui, -apple-system, BlinkMacSystemFont, sans-serif',
  },
  shape: {
    borderRadius: 18,
  },
});

const shellStyles = {
  minHeight: '100vh',
  background:
    'radial-gradient(circle at top left, rgba(79, 140, 255, 0.22), transparent 32%), linear-gradient(180deg, #08111f 0%, #0d1728 100%)',
  color: '#e8eefc',
};

function PageFrame({ title, subtitle }) {
  return (
    <Container maxWidth="md" sx={{ py: 8 }}>
      <Card sx={{ backdropFilter: 'blur(18px)', border: '1px solid rgba(255,255,255,0.08)' }}>
        <CardContent sx={{ p: { xs: 3, sm: 5 } }}>
          <Typography variant="overline" sx={{ letterSpacing: 2, color: 'primary.main' }}>
            WorkPulse
          </Typography>
          <Typography variant="h4" sx={{ mt: 1, fontWeight: 800 }}>
            {title}
          </Typography>
          <Typography sx={{ mt: 1.5, color: 'text.secondary', maxWidth: 560 }}>
            {subtitle}
          </Typography>
          <Box sx={{ mt: 4 }}>
            <Typography variant="body2" sx={{ color: 'text.secondary' }}>
              The backend is running and this frontend shell is ready for your login, register,
              and dashboard screens.
            </Typography>
          </Box>
        </CardContent>
      </Card>
    </Container>
  );
}

function Home() {
  return (
    <PageFrame
      title="Team reporting made clean"
      subtitle="A polished WorkPulse front door with room for authentication, dashboards, and profile features."
    />
  );
}

function Login() {
  return (
    <PageFrame
      title="Sign in"
      subtitle="This placeholder page confirms the app boots correctly while the real login form is connected."
    />
  );
}

function Register() {
  return (
    <PageFrame
      title="Create account"
      subtitle="This placeholder page confirms routing works while registration UI is built out."
    />
  );
}

function Dashboard({ label }) {
  return (
    <Container maxWidth="lg" sx={{ py: 8 }}>
      <Stack spacing={3}>
        <Card sx={{ border: '1px solid rgba(255,255,255,0.08)' }}>
          <CardContent sx={{ p: { xs: 3, sm: 5 } }}>
            <Typography variant="overline" sx={{ letterSpacing: 2, color: 'primary.main' }}>
              Dashboard
            </Typography>
            <Typography variant="h4" sx={{ mt: 1, fontWeight: 800 }}>
              {label}
            </Typography>
            <Typography sx={{ mt: 1.5, color: 'text.secondary' }}>
              The app is running. You can replace this shell with the real dashboard components
              next.
            </Typography>
          </CardContent>
        </Card>
      </Stack>
    </Container>
  );
}

function App() {
  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <BrowserRouter>
        <Box sx={shellStyles}>
          <AppBar position="sticky" elevation={0} sx={{ bgcolor: 'rgba(8, 17, 31, 0.72)', backdropFilter: 'blur(16px)' }}>
            <Toolbar sx={{ display: 'flex', justifyContent: 'space-between', gap: 2 }}>
              <Typography variant="h6" sx={{ fontWeight: 800 }}>
                WorkPulse
              </Typography>
              <Stack direction="row" spacing={1}>
                <Button component={Link} to="/login" color="inherit">
                  Login
                </Button>
                <Button component={Link} to="/register" variant="contained">
                  Register
                </Button>
              </Stack>
            </Toolbar>
          </AppBar>

          <Routes>
            <Route path="/" element={<Navigate to="/login" replace />} />
            <Route path="/login" element={<Login />} />
            <Route path="/register" element={<Register />} />
            <Route path="/manager/dashboard" element={<Dashboard label="Manager dashboard" />} />
            <Route path="/team-member/dashboard" element={<Dashboard label="Team member dashboard" />} />
            <Route path="*" element={<Navigate to="/login" replace />} />
          </Routes>
        </Box>
      </BrowserRouter>
    </ThemeProvider>
  );
}

export default App;